import React, { useState, useEffect, useRef } from "react";
import api from "../api/axiosInstance";
import { getSensorByUser } from "../api/sensorsapi";

// ─── KPI API calls ──────────────────────────────────────────────────────────
const createKPI = (payload) =>
  api.post("/api/KPIs", {
    KPIName: payload.name,
    KPIFormula: payload.formula,
    Frequency: payload.frequency || "5min",
  });

const fetchKPIs = () => api.get(`/api/KPIs`);

// ─── Formula evaluator ──────────────────────────────────────────────────────
const evaluateFormula = (formulaStr, latestValues) => {
  if (!formulaStr || !formulaStr.trim()) return null;
  try {
    let expr = formulaStr.replace(/sensor_(\d+)/gi, (_, id) => {
      const v = latestValues[`sensor_${id}`] ?? latestValues[`sensor_${id}`.toUpperCase()];
      return v !== undefined ? v : "NaN";
    });
    expr = expr
      .replace(/AVG\(([^)]+)\)/gi, (_, a) => {
        const ns = a.split(",").map(Number).filter((n) => !isNaN(n));
        return ns.length ? ns.reduce((s, v) => s + v, 0) / ns.length : 0;
      })
      .replace(/SUM\(([^)]+)\)/gi, (_, a) =>
        a.split(",").map(Number).filter((n) => !isNaN(n)).reduce((s, v) => s + v, 0)
      )
      .replace(/MAX\(([^)]+)\)/gi, (_, a) =>
        Math.max(...a.split(",").map(Number).filter((n) => !isNaN(n)))
      )
      .replace(/MIN\(([^)]+)\)/gi, (_, a) =>
        Math.min(...a.split(",").map(Number).filter((n) => !isNaN(n)))
      );
    // eslint-disable-next-line no-new-func
    const r = Function('"use strict"; return (' + expr + ')')();
    return isNaN(r) || !isFinite(r) ? null : Number(r).toFixed(2);
  } catch {
    return null;
  }
};

// ─── Trend data generator ───────────────────────────────────────────────────
const genTrendData = (baseVal, range) => {
  const counts = { "1h": 12, "6h": 24, "24h": 24, "7d": 7, "30d": 30 };
  const n = counts[range] || 24;
  const b = parseFloat(baseVal) || 50;
  return Array.from({ length: n }, () => +(b + (Math.random() - 0.5) * b * 0.15).toFixed(2));
};

const getTrendLabels = (range) => {
  const cfg = {
    "1h":  { n: 12, fn: (i, n) => `-${(n - i) * 5}m` },
    "6h":  { n: 24, fn: (i, n) => `-${(n - i) * 15}m` },
    "24h": { n: 24, fn: (i, n) => `-${n - i}h` },
    "7d":  { n: 7,  fn: (i) => ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"][i] },
    "30d": { n: 30, fn: (i) => `Day ${i + 1}` },
  };
  const { n, fn } = cfg[range] || cfg["24h"];
  return Array.from({ length: n }, (_, i) => fn(i, n));
};

// ─── Constants ──────────────────────────────────────────────────────────────
const ICON_MAP = {
  availability: "bi-check2-circle",
  performance: "bi-speedometer2",
  quality: "bi-award",
  oee: "bi-graph-up",
  downtime: "bi-clock-history",
};
const COLOR_MAP = ["#00c6ae","#0f8fd4","#7b5ea7","#f39c12","#e74c3c","#2ecc71","#e91e63"];
const OPERATORS = [
  { label: "+", val: " + " }, { label: "−", val: " - " },
  { label: "×", val: " * " }, { label: "÷", val: " / " },
  { label: "(", val: "(" },   { label: ")", val: ")" },
];
const FX_FUNCS = ["SUM", "AVG", "MAX", "MIN"];
const FREQUENCIES = ["1min","5min","15min","30min","1hr","6hr","12hr","24hr"];
const TREND_RANGES = ["1h","6h","24h","7d","30d"];

// ─── Chart with X & Y Axis ──────────────────────────────────────────────────
const TrendChart = ({ data, color, labels }) => {
  const ref = useRef(null);

  useEffect(() => {
    const canvas = ref.current;
    if (!canvas || !data.length) return;
    const ctx = canvas.getContext("2d");
    const W = canvas.width;
    const H = canvas.height;

    const PAD_LEFT = 42;
    const PAD_RIGHT = 10;
    const PAD_TOP = 12;
    const PAD_BOTTOM = 28;

    const plotW = W - PAD_LEFT - PAD_RIGHT;
    const plotH = H - PAD_TOP - PAD_BOTTOM;

    const min = Math.min(...data);
    const max = Math.max(...data);
    const range = max - min || 1;

    ctx.clearRect(0, 0, W, H);

    // ── Grid lines & Y-axis labels ──
    const yTicks = 4;
    ctx.strokeStyle = "rgba(150,150,150,0.15)";
    ctx.lineWidth = 1;
    ctx.font = "9px monospace";
    ctx.fillStyle = "rgba(150,150,150,0.8)";
    ctx.textAlign = "right";

    for (let i = 0; i <= yTicks; i++) {
      const val = min + (range * i) / yTicks;
      const y = PAD_TOP + plotH - (plotH * i) / yTicks;
      ctx.beginPath();
      ctx.moveTo(PAD_LEFT, y);
      ctx.lineTo(PAD_LEFT + plotW, y);
      ctx.stroke();
      ctx.fillText(val.toFixed(1), PAD_LEFT - 4, y + 3);
    }

    // ── X-axis ticks ──
    const xTickCount = Math.min(5, data.length - 1);
    ctx.textAlign = "center";
    ctx.fillStyle = "rgba(150,150,150,0.8)";
    for (let i = 0; i <= xTickCount; i++) {
      const idx = Math.round((i / xTickCount) * (data.length - 1));
      const x = PAD_LEFT + (idx / (data.length - 1)) * plotW;
      ctx.fillText(labels[idx] || "", x, H - 6);
      ctx.beginPath();
      ctx.strokeStyle = "rgba(150,150,150,0.25)";
      ctx.moveTo(x, PAD_TOP);
      ctx.lineTo(x, PAD_TOP + plotH);
      ctx.stroke();
    }

    // ── Axes ──
    ctx.strokeStyle = "rgba(150,150,150,0.35)";
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(PAD_LEFT, PAD_TOP);
    ctx.lineTo(PAD_LEFT, PAD_TOP + plotH);
    ctx.lineTo(PAD_LEFT + plotW, PAD_TOP + plotH);
    ctx.stroke();

    // ── Line ──
    ctx.beginPath();
    data.forEach((v, i) => {
      const x = PAD_LEFT + (i / (data.length - 1)) * plotW;
      const y = PAD_TOP + plotH - ((v - min) / range) * plotH;
      i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    });
    ctx.strokeStyle = color;
    ctx.lineWidth = 2;
    ctx.lineJoin = "round";
    ctx.stroke();

    // ── Fill under line ──
    const lastX = PAD_LEFT + plotW;
    const baseY = PAD_TOP + plotH;
    ctx.lineTo(lastX, baseY);
    ctx.lineTo(PAD_LEFT, baseY);
    ctx.closePath();
    ctx.fillStyle = color + "22";
    ctx.fill();

    // ── Dot on last point ──
    const lastV = data[data.length - 1];
    const dotX = PAD_LEFT + plotW;
    const dotY = PAD_TOP + plotH - ((lastV - min) / range) * plotH;
    ctx.beginPath();
    ctx.arc(dotX, dotY, 3.5, 0, Math.PI * 2);
    ctx.fillStyle = color;
    ctx.fill();

  }, [data, color, labels]);

  return (
    <canvas
      ref={ref}
      width={460}
      height={180}
      style={{ display: "block", width: "100%", height: 180 }}
    />
  );
};

// ─── TrendPopup (centered modal overlay) ────────────────────────────────────
const TrendPopup = ({ kpi, onClose }) => {
  const [range, setRange] = useState("24h");
  const [data, setData] = useState([]);
  const baseVal = kpi._liveVal;

  useEffect(() => {
    setData(genTrendData(baseVal, range));
  }, [range, baseVal]);

  const labels = getTrendLabels(range);
  const min = data.length ? Math.min(...data).toFixed(2) : "—";
  const max = data.length ? Math.max(...data).toFixed(2) : "—";
  const avg = data.length ? (data.reduce((s, v) => s + v, 0) / data.length).toFixed(2) : "—";

  return (
    // Full-screen overlay — renders above everything
    <div
      style={{
        position: "fixed", inset: 0, zIndex: 2000,
        background: "rgba(0,0,0,0.45)",
        display: "flex", alignItems: "center", justifyContent: "center",
        padding: 16,
      }}
      onClick={onClose}
    >
      <div
        style={{
          width: "100%", maxWidth: 520,
          background: "var(--sb-white)",
          border: "1px solid var(--sb-border)",
          borderRadius: 20,
          padding: 24,
          boxShadow: "0 24px 64px rgba(0,0,0,0.18)",
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 16 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{
              width: 32, height: 32, borderRadius: 8,
              background: kpi.color + "22",
              display: "flex", alignItems: "center", justifyContent: "center",
            }}>
              <i className={`bi ${kpi.icon}`} style={{ color: kpi.color, fontSize: "1rem" }} />
            </div>
            <div>
              <div style={{ fontSize: 14, fontWeight: 700, color: "var(--sb-text)" }}>{kpi.name}</div>
              <div style={{ fontSize: 11, color: "var(--sb-muted)" }}>Trend Analysis</div>
            </div>
          </div>
          <button
            onClick={onClose}
            style={{
              background: "var(--sb-light-bg)", border: "1px solid var(--sb-border)",
              borderRadius: 8, width: 30, height: 30,
              display: "flex", alignItems: "center", justifyContent: "center",
              cursor: "pointer", color: "var(--sb-muted)", fontSize: 16,
            }}
          >×</button>
        </div>

        {/* Current value */}
        <div style={{
          display: "flex", alignItems: "baseline", gap: 6,
          marginBottom: 14, padding: "10px 14px",
          background: kpi.color + "10", borderRadius: 10,
          border: `1px solid ${kpi.color}30`,
        }}>
          <span style={{ fontSize: 28, fontWeight: 800, color: kpi.color, lineHeight: 1 }}>{kpi._liveVal}</span>
          {kpi.unit && <span style={{ fontSize: 13, color: "var(--sb-muted)" }}>{kpi.unit}</span>}
          <span style={{ marginLeft: "auto", fontSize: 11, color: "var(--sb-muted)", fontFamily: "monospace" }}>
            fx: {kpi.formula}
          </span>
        </div>

        {/* Range filter */}
        <div style={{ display: "flex", gap: 6, marginBottom: 12 }}>
          {TREND_RANGES.map((r) => (
            <button
              key={r}
              onClick={() => setRange(r)}
              style={{
                flex: 1, fontSize: 11, padding: "5px 0", borderRadius: 8, fontWeight: 700,
                cursor: "pointer", border: "1px solid", transition: "all 0.15s",
                background: range === r ? kpi.color : "var(--sb-light-bg)",
                color: range === r ? "#fff" : "var(--sb-muted)",
                borderColor: range === r ? kpi.color : "var(--sb-border)",
              }}
            >{r}</button>
          ))}
        </div>

        {/* Chart with axes */}
        <div style={{
          borderRadius: 12, overflow: "hidden",
          background: "var(--sb-light-bg)",
          border: "1px solid var(--sb-border)",
          padding: "10px 8px 6px",
        }}>
          <TrendChart data={data} color={kpi.color} labels={labels} />
        </div>

        {/* Stats row */}
        <div style={{
          display: "flex", justifyContent: "space-between",
          marginTop: 12, padding: "10px 14px",
          background: "var(--sb-light-bg)", borderRadius: 10,
          border: "1px solid var(--sb-border)",
        }}>
          {[["Min", min, "var(--sb-text)"], ["Avg", avg, kpi.color], ["Max", max, "var(--sb-text)"]].map(([label, val, col]) => (
            <div key={label} style={{ textAlign: "center" }}>
              <div style={{ fontSize: 10, color: "var(--sb-muted)", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.5px" }}>{label}</div>
              <div style={{ fontSize: 16, fontWeight: 800, color: col, marginTop: 2 }}>{val}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// ─── KPI Card ────────────────────────────────────────────────────────────────
const KPICard = ({ kpi }) => {
  const [showTrend, setShowTrend] = useState(false);
  const val = kpi._liveVal;
  const noData = val === null || val === undefined || !kpi.formula || !kpi.formula.trim();

  const errorMessage = !kpi.formula || !kpi.formula.trim()
    ? "No formula configured yet."
    : val === null
    ? "Unable to compute — verify formula or sensor connection."
    : null;

  return (
    <>
      <div
        style={{
          background: noData
            ? "linear-gradient(135deg, rgba(229,62,62,0.07), rgba(252,235,235,0.6))"
            : "var(--sb-card-bg)",
          borderRadius: 16,
          border: noData ? "1.5px solid #e53e3e" : "1px solid var(--sb-border)",
          padding: 20,
          position: "relative",
          overflow: "visible",
          transition: "transform 0.2s, box-shadow 0.2s",
        }}
        onMouseEnter={(e) => {
          if (!noData) {
            e.currentTarget.style.transform = "translateY(-3px)";
            e.currentTarget.style.boxShadow = "0 12px 32px rgba(0,0,0,0.08)";
          }
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.transform = "";
          e.currentTarget.style.boxShadow = "";
        }}
      >
        {/* Top accent bar */}
        <div style={{
          position: "absolute", top: 0, left: 0, right: 0, height: 3,
          background: noData ? "#e53e3e" : kpi.color,
          borderRadius: "16px 16px 0 0",
        }} />

        {/* Icon — click to open trend */}
        <div
          onClick={() => { if (!noData) setShowTrend(true); }}
          title={noData ? undefined : "Click for trend"}
          style={{
            position: "absolute", top: 16, right: 16,
            width: 38, height: 38, borderRadius: 10,
            background: noData ? "rgba(229,62,62,0.12)" : kpi.color + "18",
            display: "flex", alignItems: "center", justifyContent: "center",
            cursor: noData ? "default" : "pointer",
            transition: "background 0.15s",
            fontSize: "1.1rem",
          }}
        >
          <i className={`bi ${kpi.icon}`} style={{ color: noData ? "#e53e3e" : kpi.color }} />
        </div>

        <div style={{ paddingRight: 52 }}>
          {/* KPI name */}
          <p style={{
            fontSize: "0.75rem", fontWeight: 700, color: "var(--sb-muted)",
            marginBottom: 6, textTransform: "uppercase", letterSpacing: "0.5px",
          }}>
            {kpi.name}
          </p>

          {noData ? (
            <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 8 }}>
              <i className="bi bi-exclamation-triangle-fill" style={{ color: "#e53e3e", fontSize: "1.1rem" }} />
              <span style={{ fontSize: "0.75rem", color: "#e53e3e", fontWeight: 600, lineHeight: 1.3 }}>
                {errorMessage}
              </span>
            </div>
          ) : (
            <div style={{ display: "flex", alignItems: "baseline", gap: 4, marginBottom: 8 }}>
              <span style={{
                fontSize: "2.2rem", fontWeight: 800, lineHeight: 1,
                color: kpi.color, letterSpacing: "-1px",
              }}>
                {val}
              </span>
              {kpi.unit && (
                <span style={{ fontSize: "0.82rem", color: "var(--sb-muted)", fontWeight: 500 }}>
                  {kpi.unit}
                </span>
              )}
            </div>
          )}

          {/* Formula display */}
          <div style={{
            display: "inline-flex", alignItems: "center", gap: 6,
            padding: "3px 10px", borderRadius: 6,
            background: "var(--sb-light-bg)",
            border: "1px solid var(--sb-border)",
            maxWidth: "100%", overflow: "hidden",
          }}>
            <span style={{ fontSize: "0.65rem", fontWeight: 800, color: kpi.color }}>fx</span>
            <span
              style={{ fontSize: "0.68rem", fontFamily: "monospace", color: "var(--sb-muted)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}
              title={kpi.formula || "No formula"}
            >
              {kpi.formula ? (kpi.formula.length > 24 ? kpi.formula.slice(0, 24) + "…" : kpi.formula) : "—"}
            </span>
          </div>

          {/* Click hint */}
          {!noData && (
            <div style={{ marginTop: 8, fontSize: "0.65rem", color: "var(--sb-muted)", fontStyle: "italic" }}>
              <i className="bi bi-graph-up me-1" style={{ color: kpi.color }} />
              Click icon for trend analysis
            </div>
          )}

          {noData && (
            <div style={{ marginTop: 8 }}>
              <span style={{
                fontSize: "0.65rem", background: "#fee2e2", color: "#b91c1c",
                padding: "2px 8px", borderRadius: 20, fontWeight: 700,
              }}>
                ⚠ No data
              </span>
            </div>
          )}
        </div>
      </div>

      {/* Trend popup — rendered as a full-screen overlay, outside the card */}
      {showTrend && (
        <TrendPopup kpi={kpi} onClose={() => setShowTrend(false)} />
      )}
    </>
  );
};

// ─── KPIManagement ──────────────────────────────────────────────────────────
const KPIManagement = () => {
  const userId = localStorage.getItem("sb_userId");
  const connectionId = localStorage.getItem("sb_connectionId");

  const [kpis, setKpis] = useState([]);
  const [loadingKpis, setLoadingKpis] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState({ name: "", formula: "", unit: "", frequency: "5min", icon: "bi-graph-up", color: "#00c6ae" });
  const [errors, setErrors] = useState({});
  const [successMsg, setSuccessMsg] = useState("");
  const [errMsg, setErrMsg] = useState("");
  const [sensors, setSensors] = useState([]);
  const [sensorSearch, setSensorSearch] = useState("");
  const [kpiSearch, setKpiSearch] = useState("");
  const [liveValues, setLiveValues] = useState({
    sensor_1: 92.5, sensor_2: 87.3, sensor_3: 4.2,
    sensor_4: 98.1, sensor_5: 65.0, sensor_6: 2800,
    availability: 92.5, performance: 87.3, quality: 98.1,
    OEE: 79.4, downtime: 3.2,
  });

  // ── Load KPIs ─────────────────────────────────────────────────────────────
  const loadKPIs = async () => {
    if (!userId) { setLoadingKpis(false); return; }
    setLoadingKpis(true);
    try {
      const res = await fetchKPIs();
      const data = Array.isArray(res.data) ? res.data : res.data?.data ?? [];
      setKpis(data.map((k, i) => ({
        id: k.kpiId,
        name: k.kpiName,
        formula: k.kpiFormula,
        frequency: k.frequency,
        isActive: k.isActive,
        createdAt: k.createdAt,
        icon: ICON_MAP[k.kpiName?.toLowerCase()] || "bi-graph-up",
        color: COLOR_MAP[i % COLOR_MAP.length],
        unit: "",
        fromApi: true,
      })));
    } catch (e) {
      setErrMsg(e?.response?.data?.message || "Failed to load KPIs. Please try again.");
      setTimeout(() => setErrMsg(""), 4000);
    } finally { setLoadingKpis(false); }
  };

  useEffect(() => { loadKPIs(); }, [userId]);

  // ── Simulated live values ─────────────────────────────────────────────────
  useEffect(() => {
    const iv = setInterval(() => {
      setLiveValues((p) => {
        const next = { ...p };
        Object.keys(next).forEach((k) => {
          next[k] = +(next[k] * (0.95 + Math.random() * 0.1)).toFixed(2);
        });
        return next;
      });
    }, 5000);
    return () => clearInterval(iv);
  }, []);

  // ── Load sensors via connectionId ─────────────────────────────────────────
  useEffect(() => {
    const load = async () => {
      if (!connectionId) {
        console.warn("No connectionId found in localStorage (key: sb_connectionId)");
        return;
      }
      try {
        console.log("Fetching sensors for connectionId:", connectionId);
        const res = await getSensorByUser(connectionId);
        const list = Array.isArray(res.data) ? res.data : res.data?.data ?? [];
        console.log("Sensors received:", list);
        setSensors(list.map((s) => ({
          id: s.sensorId ?? s.id,
          name: s.sensorName ?? s.name,
          quantity: s.quantity,
          unit: s.unit,
        })));
      } catch (e) {
        console.error("Sensor API failed:", e?.response?.status, e?.response?.data || e.message);
      }
    };
    load();
  }, [connectionId]);

  // ── Insert into formula ────────────────────────────────────────────────────
  const insertToFormula = (text) => setForm((f) => ({ ...f, formula: f.formula + text }));

  // ── Insert function with placeholder ──────────────────────────────────────
  // e.g. clicking AVG() when a sensor chip is already selected will wrap it
  // but if no sensor — insert AVG(sensor_x) as a placeholder hint
  const insertFunction = (fnName) => {
    setForm((f) => ({ ...f, formula: f.formula + `${fnName}(` }));
  };

  // ── Add KPI ───────────────────────────────────────────────────────────────
  const handleAddKpi = async () => {
    const errs = {};
    if (!form.name.trim()) errs.name = "KPI name is required.";
    if (!form.formula.trim()) errs.formula = "Formula is required.";
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setSaving(true);
    try {
      await createKPI(form);
      setForm({ name: "", formula: "", unit: "", frequency: "5min", icon: "bi-graph-up", color: "#00c6ae" });
      setShowForm(false); setSensorSearch(""); setErrors({});
      setSuccessMsg(`KPI "${form.name}" created successfully!`);
      setTimeout(() => setSuccessMsg(""), 3500);
      await loadKPIs();
    } catch (e) {
      setErrMsg(e?.response?.data?.message || "Failed to create KPI. Please check your inputs and try again.");
      setTimeout(() => setErrMsg(""), 4000);
    } finally { setSaving(false); }
  };

  const enrichedKpis = kpis.map((k) => ({
    ...k,
    _liveVal: evaluateFormula(k.formula, liveValues),
  }));

  const filteredKpis = enrichedKpis.filter((k) =>
    k.name.toLowerCase().includes(kpiSearch.toLowerCase())
  );

  const filteredSensors = sensors.filter((s) =>
    s.name?.toLowerCase().includes(sensorSearch.toLowerCase())
  );

  const preview = form.formula ? evaluateFormula(form.formula, liveValues) : null;
  const formulaIsInvalid = form.formula.trim() && preview === null;

  return (
    <div>
      <style>{`
        @keyframes pulseDot {
          0%,100% { opacity:1; transform:scale(1); }
          50% { opacity:0.4; transform:scale(0.7); }
        }
        .op-btn {
          width:40px; height:36px; border:1px solid var(--sb-border);
          border-radius:8px; background:var(--sb-light-bg); color:var(--sb-text);
          font-weight:700; font-size:1rem; cursor:pointer;
          display:inline-flex; align-items:center; justify-content:center;
          transition:background 0.15s, border-color 0.15s;
        }
        .op-btn:hover { background:var(--sb-accent); color:#fff; border-color:var(--sb-accent); }
        .fn-btn {
          padding:4px 12px; border-radius:20px; border:1px solid var(--sb-border);
          background:var(--sb-light-bg); color:var(--sb-accent);
          font-size:0.78rem; font-weight:700; cursor:pointer; font-family:monospace;
          transition:background 0.15s;
        }
        .fn-btn:hover { background:var(--sb-accent); color:#fff; }
        .sensor-chip {
          display:inline-flex; align-items:center; gap:5px;
          padding:4px 12px; border-radius:20px;
          background:var(--sb-light-bg); border:1px solid var(--sb-border);
          color:var(--sb-text); font-size:0.78rem; font-weight:600;
          cursor:pointer; transition:all 0.15s; white-space:nowrap;
        }
        .sensor-chip:hover { background:var(--sb-accent); color:#fff; border-color:var(--sb-accent); }
        .fx-bar {
          display:flex; align-items:center; background:var(--sb-light-bg);
          border:1.5px solid var(--sb-border); border-radius:10px; padding:8px 14px;
          transition:border-color 0.2s;
        }
        .fx-bar:focus-within { border-color:var(--sb-accent); background:var(--sb-white); }
        .fx-bar input { flex:1; background:none; border:none; outline:none; color:var(--sb-text); font-family:monospace; font-size:0.9rem; }
        .modal-overlay {
          position:fixed; inset:0; background:rgba(0,0,0,0.45);
          display:flex; align-items:center; justify-content:center;
          z-index:1050; padding:16px;
        }
        .modal-box {
          width:100%; max-width:760px; background:var(--sb-white);
          border-radius:20px; box-shadow:0 24px 60px rgba(0,0,0,0.15); overflow:hidden;
        }
        .modal-header { padding:20px 28px 16px; border-bottom:1px solid var(--sb-border); display:flex; align-items:center; justify-content:space-between; }
