        .modal-footer { padding:16px 28px; border-top:1px solid var(--sb-border); display:flex; justify-content:flex-end; gap:10px; }
        .field-label { font-size:0.7rem; font-weight:700; letter-spacing:0.8px; text-transform:uppercase; color:var(--sb-muted); margin-bottom:5px; display:block; }
