        .kpi-search-input { background:var(--sb-light-bg); border:1px solid var(--sb-border); border-radius:50px; padding:8px 16px 8px 36px; color:var(--sb-text); font-size:0.85rem; outline:none; width:220px; transition:border-color 0.2s; }
        .kpi-search-input:focus { border-color:var(--sb-accent); background:var(--sb-white); }

